{
  "summary": "Daily Hacker News top 5 stories to Notion",
  "nodes": [
    {
      "id": "trigger_schedule",
      "type": "schedule",
      "config": {
        "cron": "0 8 * * *",
        "timezone": "UTC"
      }
    },
    {
      "id": "http_topstories",
      "type": "http_request",
      "config": {
        "method": "GET",
        "url": "https://hacker-news.firebaseio.com/v0/topstories.json",
        "response_format": "json"
      }
    },
    {
      "id": "function_fetch_items",
      "type": "function",
      "config": {
        "code": "const ids = input.slice(0,10); return Promise.all(ids.map(id => fetch(`https://hacker-news.firebaseio.com/v0/item/${id}.json`).then(r=>r.json())));",
        "language": "javascript"
      }
    },
    {
      "id": "sort_by_score",
      "type": "sort",
      "config": {
        "field": "score",
        "order": "descending"
      }
    },
    {
      "id": "limit_top5",
      "type": "limit",
      "config": {
        "count": 5
      }
    },
    {
      "id": "notion_create_pages",
      "type": "notion",
      "config": {
        "database_id": "your_database_id",
        "properties": {
          "Title": {
            "title": [
              {
                "text": {
                  "content": "{{sort_by_score.output.title}}"
                }
              }
            ]
          },
          "URL": {
            "url": "{{sort_by_score.output.url}}"
          },
          "Score": {
            "number": "{{sort_by_score.output.score}}"
          }
        },
        "action": "create"
      }
    }
  ],
  "connections": [
    {
      "source": "trigger_schedule",
      "target": "http_topstories",
      "source_output": "trigger",
      "target_input": "input"
    },
    {
      "source": "http_topstories",
      "target": "function_fetch_items",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "function_fetch_items",
      "target": "sort_by_score",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "sort_by_score",
      "target": "limit_top5",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "limit_top5",
      "target": "notion_create_pages",
      "source_output": "output",
      "target_input": "input"
    }
  ],
  "required_credentials": [
    "notion"
  ],
  "validation_status": "valid"
}

