{
  "summary": "Weekly completed tasks report to Pipedrive and Zoho",
  "nodes": [
    {
      "id": "trigger_schedule_weekly",
      "type": "schedule",
      "config": {
        "cron": "0 0 * * 0",
        "timezone": "UTC"
      }
    },
    {
      "id": "clickup_tasks",
      "type": "clickup",
      "config": {
        "list_id": "your_list_id",
        "status": "completed",
        "action": "get_tasks"
      }
    },
    {
      "id": "aggregate_by_assignee",
      "type": "aggregate",
      "config": {
        "group_by": "assignee.id",
        "fields": {
          "assignee_name": {
            "first": "assignee.username"
          },
          "task_count": {
            "count": "*"
          },
          "task_titles": {
            "collect": "name"
          }
        }
      }
    },
    {
      "id": "function_item_deals",
      "type": "function_item",
      "config": {
        "items": "{{aggregate_by_assignee.output}}",
        "function": "return { title: item.assignee_name + ' - ' + item.task_count + ' tasks', value: item.task_count * 100 }"
      }
    },
    {
      "id": "pipedrive_create_deal",
      "type": "pipedrive",
      "config": {
        "action": "create_deal",
        "title": "{{function_item_deals.output.title}}",
        "value": "{{function_item_deals.output.value}}"
      }
    },
    {
      "id": "zoho_update_note",
      "type": "zoho",
      "config": {
        "module": "Deals",
        "id": "{{pipedrive_create_deal.output.id}}",
        "note": "Tasks completed this week: {{function_item_deals.output.task_titles.join(', ')}}"
      }
    }
  ],
  "connections": [
    {
      "source": "trigger_schedule_weekly",
      "target": "clickup_tasks",
      "source_output": "trigger",
      "target_input": "input"
    },
    {
      "source": "clickup_tasks",
      "target": "aggregate_by_assignee",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "aggregate_by_assignee",
      "target": "function_item_deals",
      "source_output": "output",
      "target_input": "items"
    },
    {
      "source": "function_item_deals",
      "target": "pipedrive_create_deal",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "pipedrive_create_deal",
      "target": "zoho_update_note",
      "source_output": "output",
      "target_input": "input"
    }
  ],
  "required_credentials": [
    "clickup",
    "pipedrive",
    "zoho"
  ],
  "validation_status": "valid"
}

{
  "summary": "Chat‑triggered webpage summarizer and LinkedIn poster",
  "nodes": [
    {
      "id": "trigger_chat_url",
      "type": "chat_trigger",
      "config": {
        "platform": "slack",
        "channel": "#web-summary"
      }
    },
    {
      "id": "extract_url",
      "type": "code",
      "config": {
        "code": "const urlRegex = /(https?:\\/\\/[^\\s]+)/g;\nconst match = input.message.match(urlRegex);\nreturn { url: match ? match[0] : null };",
        "language": "javascript"
      }
    },
    {
      "id": "if_url_exists",
      "type": "if",
      "config": {
        "condition": "{{extract_url.output.url}} != null"
      }
    },
    {
      "id": "http_fetch_page",
      "type": "http_request",
      "config": {
        "method": "GET",
        "url": "{{extract_url.output.url}}",
        "response_format": "text"
      }
    },
    {
      "id": "ai_summarize",
      "type": "ai_chat_model",
      "config": {
        "model": "gpt-3.5-turbo",
        "messages": [
          {
            "role": "system",
            "content": "Summarize the following webpage content in 2 sentences."
          },
          {
            "role": "user",
            "content": "{{http_fetch_page.output}}"
          }
        ],
        "temperature": 0.3
      }
    },
    {
      "id": "linkedin_post",
      "type": "linkedin",
      "config": {
        "text": "Summary: {{ai_summarize.output.choices[0].message.content}}\n\nOriginal: {{extract_url.output.url}}",
        "visibility": "PUBLIC"
      }
    }
  ],
  "connections": [
    {
      "source": "trigger_chat_url",
      "target": "extract_url",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "extract_url",
      "target": "if_url_exists",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "if_url_exists",
      "target": "http_fetch_page",
      "source_output": "true",
      "target_input": "input"
    },
    {
      "source": "http_fetch_page",
      "target": "ai_summarize",
      "source_output": "output",
      "target_input": "input"
    },
    {
      "source": "ai_summarize",
      "target": "linkedin_post",
      "source_output": "output",
      "target_input": "input"
    }
  ],
  "required_credentials": [
    "linkedin"
  ],
  "validation_status": "valid"
}

