{
  "summary": "Hourly GitHub issue triage to Telegram",
  "nodes": [
    {
      "id": "schedule_0_7592b8a7",
      "type": "schedule",
      "config": {
        "cron": "0 * * * *",
        "timezone": "UTC"
      }
    },
    {
      "id": "github_0_b9dd6d4d",
      "type": "github",
      "config": {
        "repo": "myorg/myrepo",
        "state": "open",
        "action": "list_issues"
      }
    },
    {
      "id": "function_item_0_06973405",
      "type": "function_item",
      "config": {
        "items": "{{github_list_issues.output}}",
        "function": "return item;"
      }
    },
    {
      "id": "switch_0_2905b959",
      "type": "switch",
      "config": {
        "value": "{{function_item_issues.output.labels[0].name}}",
