      "id": "schedule_0_60e1bfd7",
      "type": "schedule",
      "config": {
        "cron": "0 0 * * 0",
        "timezone": "UTC"
      }
    },
    {
      "id": "clickup_0_f430bf8d",
      "type": "clickup",
      "config": {
        "list_id": "your_list_id",
        "status": "completed",
        "action": "get_tasks"
      }
    },
    {
      "id": "aggregate_0_d5b4881b",
      "type": "aggregate",
      "config": {
        "group_by": "assignee.id",
        "fields": {
          "assignee_name": {
            "first": "assignee.username"
          },
          "task_count": {
            "count": "*"
          },
          "task_titles": {
            "collect": "name"
          }
        }
      }
    },
    {
      "id": "function_item_0_8332ca72",
      "type": "function_item",
      "config": {
        "items": "{{aggregate_by_assignee.output}}",
        "function": "return { title: item.assignee_name + ' - ' + item.task_count + ' tasks', value: item.task_count * 100 }"
      }
    },
    {
      "id": "pipedrive_0_198429e3",
      "type": "pipedrive",
      "config": {
        "action": "create_deal",
        "title": "{{function_item_deals.output.title}}",
        "value": "{{function_item_deals.output.value}}"
      }
    },
    {
      "id": "zoho_0_c2294406",
